package com.enterprise.banking.service;

import com.enterprise.banking.model.BankingTransaction;
import com.enterprise.banking.model.TransactionResponse;

import javax.jws.WebService;
import java.math.BigDecimal;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;
import java.util.regex.Pattern;

@WebService(
    serviceName = "BankingService",
    portName = "BankingServicePort",
    endpointInterface = "com.enterprise.banking.service.BankingServicePort",
    targetNamespace = "http://enterprise.com/banking/service"
)
public class BankingServiceImpl implements BankingServicePort {

    private static final Logger LOGGER = Logger.getLogger(BankingServiceImpl.class.getName());
    private static final Map<String, BankingTransaction> transactionStore = new ConcurrentHashMap<>();
    private static final Map<String, String> transactionStatusStore = new ConcurrentHashMap<>();

    private static final Pattern ACCOUNT_PATTERN = Pattern.compile("^[A-Z]{2}\\d{2}[A-Z0-9]{4}\\d{7}([A-Z0-9]?){0,16}$");
    private static final BigDecimal MAX_TRANSACTION_AMOUNT = new BigDecimal("1000000.00");
    private static final BigDecimal MIN_TRANSACTION_AMOUNT = new BigDecimal("0.01");

    @Override
    public TransactionResponse processTransaction(BankingTransaction transaction) {
        LOGGER.info("Processing transaction: " + sanitizeLogInput(transaction.getTransactionId()));

        // Validate transaction
        String validationError = validateTransaction(transaction);
        if (validationError != null) {
            LOGGER.warning("Transaction validation failed: " + sanitizeLogInput(validationError));
            return new TransactionResponse(
                transaction.getTransactionId(),
                "REJECTED",
                validationError,
                null
            );
        }

        // Check for duplicate transaction IDs
        if (transactionStore.containsKey(transaction.getTransactionId())) {
            LOGGER.warning("Duplicate transaction ID: " + sanitizeLogInput(transaction.getTransactionId()));
            return new TransactionResponse(
                transaction.getTransactionId(),
                "REJECTED",
                "Duplicate transaction ID",
                null
            );
        }

        String confirmationCode = UUID.randomUUID().toString();
        transactionStore.put(transaction.getTransactionId(), transaction);
        transactionStatusStore.put(transaction.getTransactionId(), "COMPLETED");

        LOGGER.info("Transaction processed successfully: " + sanitizeLogInput(transaction.getTransactionId()));

        return new TransactionResponse(
            transaction.getTransactionId(),
            "COMPLETED",
            "Transaction processed successfully",
            confirmationCode
        );
    }

    @Override
    public TransactionResponse getTransactionStatus(String transactionId) {
        LOGGER.info("Getting status for transaction: " + sanitizeLogInput(transactionId));

        if (transactionId == null || transactionId.trim().isEmpty()) {
            return new TransactionResponse(null, "ERROR", "Transaction ID is required", null);
        }

        String status = transactionStatusStore.get(transactionId);
        if (status == null) {
            return new TransactionResponse(transactionId, "NOT_FOUND", "Transaction not found", null);
        }

        return new TransactionResponse(transactionId, status, "Status retrieved successfully", null);
    }

    @Override
    public TransactionResponse cancelTransaction(String transactionId) {
        LOGGER.info("Cancelling transaction: " + sanitizeLogInput(transactionId));

        if (transactionId == null || transactionId.trim().isEmpty()) {
            return new TransactionResponse(null, "ERROR", "Transaction ID is required", null);
        }

        String status = transactionStatusStore.get(transactionId);
        if (status == null) {
            return new TransactionResponse(transactionId, "NOT_FOUND", "Transaction not found", null);
        }

        if ("CANCELLED".equals(status)) {
            return new TransactionResponse(transactionId, "ERROR", "Transaction already cancelled", null);
        }

        transactionStatusStore.put(transactionId, "CANCELLED");
        return new TransactionResponse(transactionId, "CANCELLED", "Transaction cancelled successfully", null);
    }

    private String validateTransaction(BankingTransaction transaction) {
        if (transaction == null) {
            return "Transaction cannot be null";
        }
        if (transaction.getTransactionId() == null || transaction.getTransactionId().trim().isEmpty()) {
            return "Transaction ID is required";
        }
        if (transaction.getFromAccount() == null || transaction.getFromAccount().trim().isEmpty()) {
            return "Source account is required";
        }
        if (transaction.getToAccount() == null || transaction.getToAccount().trim().isEmpty()) {
            return "Destination account is required";
        }
        if (transaction.getAmount() == null) {
            return "Amount is required";
        }
        if (transaction.getAmount().compareTo(MIN_TRANSACTION_AMOUNT) < 0) {
            return "Amount must be at least " + MIN_TRANSACTION_AMOUNT;
        }
        if (transaction.getAmount().compareTo(MAX_TRANSACTION_AMOUNT) > 0) {
            return "Amount exceeds maximum allowed: " + MAX_TRANSACTION_AMOUNT;
        }
        if (transaction.getFromAccount().equals(transaction.getToAccount())) {
            return "Source and destination accounts cannot be the same";
        }
        if (!ACCOUNT_PATTERN.matcher(transaction.getFromAccount()).matches()) {
            return "Invalid source account format";
        }
        if (!ACCOUNT_PATTERN.matcher(transaction.getToAccount()).matches()) {
            return "Invalid destination account format";
        }
        if (transaction.getCurrency() == null || transaction.getCurrency().trim().isEmpty()) {
            return "Currency is required";
        }
        if (!transaction.getCurrency().matches("^[A-Z]{3}$")) {
            return "Invalid currency code";
        }
        return null;
    }

    private String sanitizeLogInput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "").replaceAll("[^a-zA-Z0-9\\-_. ]", "");
    }
}

